import React, { useState } from 'react';
import './CliForm.css';
const ClientForm = ({ onAdd }) => {
  const [formData, setFormData] = useState({
    nomCli: '',
    prenomCli: '',
    adressCli: '',
    telCli: '',
    sexe: ''
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const response = await fetch('http://localhost:3001/clients', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!response.ok) throw new Error('Erreur lors de l\'ajout');

      const data = await response.json();
      console.log('Ajout réussi:', data);

      if (onAdd) onAdd(); // Pour recharger la liste si besoin

      setFormData({
        nomCli: '',
        prenomCli: '',
        adressCli: '',
        telCli: '',
        sexe: ''
      });
    } catch (err) {
      console.error('Erreur :', err);
      alert("Échec de l'ajout du client.");
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ marginBottom: '20px' }}>
      <input name="nomCli" placeholder="Nom" value={formData.nomCli} onChange={handleChange} required />
      <input name="prenomCli" placeholder="Prénom" value={formData.prenomCli} onChange={handleChange} required />
      <input name="adressCli" placeholder="Adresse" value={formData.adressCli} onChange={handleChange} required />
      <input name="telCli" placeholder="Téléphone" value={formData.telCli} onChange={handleChange} required />
      <input name="sexe" placeholder="Sexe (H/F)" value={formData.sexe} onChange={handleChange} required />
      <button type="submit">Ajouter</button>
    </form>
  );
};

export default ClientForm;
